import{_ as l,o as i,c as e,a2 as o}from"./chunks/framework.ZhLefgN8.js";const c=JSON.parse('{"title":"App 登录失败怎么办","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"troubleshooting/login-failure.md","filePath":"zh-CN/troubleshooting/login-failure.md"}'),r={name:"troubleshooting/login-failure.md"};function t(p,a,n,h,s,d){return i(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="app-登录失败怎么办" tabindex="-1">App 登录失败怎么办 <a class="header-anchor" href="#app-登录失败怎么办" aria-label="Permalink to &quot;App 登录失败怎么办&quot;">​</a></h1><p>无法登录长桥 App 时，根据具体表现定位原因并处理。</p><h2 id="收不到验证码" tabindex="-1">收不到验证码 <a class="header-anchor" href="#收不到验证码" aria-label="Permalink to &quot;收不到验证码&quot;">​</a></h2><p>使用手机号 + OTP 方式登录时收不到验证码，请参阅 <a href="./收不到短信验证码">收不到短信验证码</a> 排查。</p><h2 id="提示密码错误" tabindex="-1">提示密码错误 <a class="header-anchor" href="#提示密码错误" aria-label="Permalink to &quot;提示密码错误&quot;">​</a></h2><p>使用手机号 + 密码、Login ID 或邮箱方式登录时提示密码错误：</p><ol><li>点击登录页的「Forgot Password」重置密码</li><li>系统会向绑定手机号或邮箱发送验证码</li><li>完成验证后设置新密码</li></ol><p>如果绑定的手机号已不再使用，无法接收验证码，请联系客服进行人工身份核验。</p><h2 id="提示账户异常或已冻结" tabindex="-1">提示账户异常或已冻结 <a class="header-anchor" href="#提示账户异常或已冻结" aria-label="Permalink to &quot;提示账户异常或已冻结&quot;">​</a></h2><p>登录后提示账户异常、被冻结或被限制：</p><ol><li>记录页面上显示的具体提示文字</li><li>点击页面上的「联系客服」或前往 App → 我的 → 帮助与客服</li><li>提供账户手机号和异常提示内容，由客服核查原因</li></ol><p>常见原因包括：多次输错密码触发安全锁定、账户被风控限制、合规审查等。</p><h2 id="第三方登录无法匹配账户" tabindex="-1">第三方登录无法匹配账户 <a class="header-anchor" href="#第三方登录无法匹配账户" aria-label="Permalink to &quot;第三方登录无法匹配账户&quot;">​</a></h2><p>使用支付宝、Google 或 Facebook 登录后提示账户不存在或创建了新账号：</p><ul><li>第三方登录以授权账号关联的手机号或邮箱匹配长桥账户</li><li>如果当前第三方账号关联的号码与注册时使用的手机号不同，系统无法匹配，会创建新账号</li><li>切换回手机号 + OTP 方式登录原账户，然后在「我的 → 账户安全」绑定第三方账号</li></ul><h2 id="app-无法打开或加载异常" tabindex="-1">App 无法打开或加载异常 <a class="header-anchor" href="#app-无法打开或加载异常" aria-label="Permalink to &quot;App 无法打开或加载异常&quot;">​</a></h2><p>如果 App 能打开但登录页无法加载，或点击登录没有响应：</p><ol><li>检查网络连接，切换到其他 Wi-Fi 或移动数据重试</li><li>如使用 VPN 或代理，关闭后重试</li><li>强制关闭 App 后重新打开</li><li>如问题持续，参阅 <a href="./APP网络连接排查">APP 网络连接排查</a></li></ol><h2 id="提示「该账户在其他设备登录」" tabindex="-1">提示「该账户在其他设备登录」 <a class="header-anchor" href="#提示「该账户在其他设备登录」" aria-label="Permalink to &quot;提示「该账户在其他设备登录」&quot;">​</a></h2><p>长桥支持多设备同时登录，此提示通常表示账户安全策略触发，如怀疑账户被盗用：</p><ol><li>立即修改密码：登录后前往「我的 → 账户安全 → 修改密码」</li><li>在「账户安全 → 登录设备管理」下线可疑设备</li><li>如无法登录，联系客服冻结账户</li></ol><h2 id="仍无法解决" tabindex="-1">仍无法解决 <a class="header-anchor" href="#仍无法解决" aria-label="Permalink to &quot;仍无法解决&quot;">​</a></h2><p>点击登录页右上角「Get Help」直接联系客服，或：</p><ul><li><strong>在线客服</strong>：长桥 App → 我的 → 帮助与客服 → 在线客服</li><li><strong>客服热线</strong>：4000712688</li></ul>',24)])])}const b=l(r,[["render",t]]);export{c as __pageData,b as default};
